;
var BLOCKED_TIME = "hot_blocker_blocked_time"
var BLOCKED_FORE = "hot_blocker_block_minutes"
var FAIL_COUNTER = "hot_blocker_counter"
var $block = document.getElementById("block");

function incrementCounter(b) {
    var a;
    b = null != (a = hotspotConfig["block-time"]) ? a : 5;
    var c;
    a = null != (c = getCookieOrNull(FAIL_COUNTER)) ? c : 0;
    a = parseInt(a) + 1;
    setCookie(FAIL_COUNTER, a, b);
    return a;
}

function checkFailsCount(b, a) {
    var c, d = null != (c = hotspotConfig["try-count"]) ? c : 5;
    if(a >= d) {
        var e;
        c = null != (e = hotspotConfig["block-time"]) ? e : 5;
        e = timeStamp();
        setCookie(BLOCKED_TIME, e, c);
        setCookie(BLOCKED_FORE, c, c);
        redirectToBlockPage();
    }
}

function resetCounter() {
    setCookie(BLOCKED_TIME, "", -1);
    setCookie(FAIL_COUNTER, "", -1);
}

function redirectToBlockPage() {
    if($block != null) {
        var $loginSubmit = document.querySelector(".login-submit");
        showParentElement($loginSubmit, $block);
        var countDownSpan = document.querySelector("span[count-down-span]");
        if(countDownSpan) {
            initCountDown(countDownSpan);
        }
    }
}

function checkIsBlocked() {
    if(getCookieOrNull(BLOCKED_TIME) == null) {
        return false;
    }
    redirectToBlockPage();
    return true;
}

function setCookie(b, a, c) {
    var d = new Date();
    if(c && c > 0) {
        d.setTime(d.getTime() + 60000 * c);
        c = "expires=" + d.toUTCString();
    } else if(c === -1) {
        c = "expires=Thu, 01 Jan 1970 00:00:00 UTC";
    } else {
        c = "";
    }
    document.cookie = b + "=" + a + ";" + c + ";path=/";
}

function getCookieOrNull(b) {
    var cookies = document.cookie.split(";");
    for(var i = 0; i < cookies.length; i++) {
        var cookie = cookies[i].trim();
        var parts = cookie.split("=");
        if(parts[0] === b) {
            return parts[1];
        }
    }
    return null;
}

function timeStamp() {
    return Math.floor((new Date()).getTime() / 1000);
}

function initCountDown(b) {
    if(b != null) {
        var a = getCookieOrNull(BLOCKED_TIME);
        if(a === null) {
            showLoginPage();
            hideBlockPage();
        } else {
            var blockedFore = getCookieOrNull(BLOCKED_FORE);
            var c = 60 * (blockedFore ? parseInt(blockedFore) : 5) + parseInt(a);
            var interval = setInterval(function() {
                var currentTime = timeStamp();
                var remaining = c - currentTime;
                if(remaining > 0) {
                    var minutes = Math.floor(remaining / 60);
                    var seconds = remaining % 60;
                    b.innerHTML = minutes + " دقائق و " + seconds + " ثانية";
                } else {
                    clearInterval(interval);
                    showLoginPage();
                    hideBlockPage();
                }
            }, 1000);
            var remainingInit = c - timeStamp();
            if(remainingInit > 0) {
                var minutesInit = Math.floor(remainingInit / 60);
                var secondsInit = remainingInit % 60;
                b.innerHTML = minutesInit + " دقائق و " + secondsInit + " ثانية";
            }
        }
    }
}

function hideBlockPage() {
    if($block != null) {
        $block.style.display = "none";
        $block.classList.add("inactive");
    }
}

function showLoginPage() {
    var loginElement = document.getElementById("login");
    if(loginElement) {
        loginElement.style.display = "block";
        loginElement.classList.remove("inactive");
    }
}

function showParentElement(a, b) {
    if(a) a.classList.add("success");
    setTimeout(function() {
        if(b) {
            b.style.display = "block";
            b.classList.add("active");
        }
    }, 500);
    setTimeout(function() {
        var statusElement = document.getElementById("status");
        if(statusElement && statusElement.classList.contains("active") && b !== statusElement) {
            if(statusElement) {
                statusElement.style.display = "none";
                statusElement.classList.remove("active");
            }
        } else if(loginElement) {
            if(loginElement) {
                loginElement.style.display = "none";
                loginElement.classList.add("inactive");
            }
        }
        if(a) {
            a.classList.remove("success");
            a.classList.remove("processing");
        }
    }, 430);
}

document.addEventListener("DOMContentLoaded", function() {
    checkIsBlocked();
}, false);
